// Extract structured data from demo transcript using regex
// This is the equivalent of lib/engine.ts extractStructuredData()

const transcript = $input.item.json.body.transcript;
const accountId = $input.item.json.body.accountId;
const now = new Date().toISOString();
const questions = [];

function findValue(text, ...patterns) {
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) return match[1].trim();
  }
  return '';
}

function findList(text, ...patterns) {
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) {
      return match[1].split(/[,;]/).map(s => s.trim()).filter(Boolean);
    }
  }
  return [];
}

// Extract fields
const companyName = findValue(transcript,
  /(?:business\s*name|company\s*name|company)\s*(?:is|:)\s*(.+?)(?:\.|,|\n|$)/i,
  /(?:we\s*are|I\s*(?:run|own|operate))\s+(.+?)(?:\.|,|\n|$)/i
);
if (!companyName) questions.push('What is the business/company name?');

const ownerName = findValue(transcript,
  /(?:my\s*name\s*is|owner(?:'s)?\s*name|name)\s*(?:is|:)?\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3})/i
);

const phone = findValue(transcript,
  /(?:phone|number|call\s*(?:us|me)\s*at)\s*(?:is|:)?\s*([\d\-\(\)\+\s]{7,})/i
);

const email = findValue(transcript,
  /(?:email|e-mail)\s*(?:is|:)?\s*([\w.\-+]+@[\w.\-]+\.\w+)/i
);

const officeAddress = findValue(transcript,
  /(?:office\s*)?(?:address|location|located)\s*(?:is|:)?\s*(.+?)(?:\.\s|\n|$)/i
);

const timezone = findValue(transcript,
  /(?:timezone|time\s*zone)\s*(?:is|:)?\s*(.+?)(?:\.|,|\n|$)/i,
  /\b(Eastern|Central|Mountain|Pacific|EST|CST|MST|PST|ET|CT|MT|PT)\b/i
);

const servicesSupported = findList(transcript,
  /(?:services?\s*(?:offered|supported|we\s*offer|include|provided|we\s*provide))\s*(?:are|:)?\s*(.+?)(?:\.\s|\n|$)/i
);

const emergencyDef = findList(transcript,
  /(?:emergency|emergencies)\s*(?:definition|defined\s*as|include|are|means?|triggers?|:)\s*(.+?)(?:\.\s|\n|$)/i
);

const accountMemo = {
  account_id: accountId,
  company_name: companyName,
  version: 1,
  created_at: now,
  updated_at: now,
  type: 'demo',
  status: 'active',
  business_hours: {
    days: 'Monday-Friday',
    start: '8:00 AM',
    end: '5:00 PM',
    timezone: timezone || 'Local'
  },
  office_address: officeAddress,
  services_supported: servicesSupported,
  emergency_definition: emergencyDef,
  emergency_routing_rules: [],
  non_emergency_routing_rules: 'Take caller name, phone number, and message. Schedule callback during business hours.',
  call_transfer_rules: {
    timeout_seconds: 30,
    max_retries: 2,
    message_if_fails: 'I\'m sorry, I wasn\'t able to connect you. Can I take your name and number so someone can call you back shortly?'
  },
  integration_constraints: [],
  after_hours_flow_summary: 'Greet caller, determine if emergency, if yes collect name/number/address and attempt dispatch, if no take message and assure next-day callback.',
  office_hours_flow_summary: 'Greet caller, determine purpose, collect name and number, schedule appointment or transfer to team member, confirm next steps, close.',
  owner_name: ownerName,
  phone: phone,
  email: email,
  notes: '',
  questions_or_unknowns: questions
};

return { json: { accountMemo, accountId } };
